#include <vector>

#include "eas_common.hpp"

using namespace sqlgen;
using namespace sqlgen::literals;

// Helper to map table name to C++ type
inline const std::string& normalize_table_name(const std::string& name) {
  return name;
}

template <typename F>
void with_table_type(const std::string& table_name, F&& f) {
  const auto& n = normalize_table_name(table_name);
  if (n == "Student" || n == "student") {
    f.template operator()<Student>();
  } else if (n == "Course" || n == "course") {
    f.template operator()<Course>();
  } else if (n == "Score" || n == "score") {
    f.template operator()<Score>();
  } else if (n == "Major" || n == "major") {
    f.template operator()<Major>();
  } else {
    throw std::runtime_error("Unknown table name: " + table_name);
  }
}

// Generic add function – T is the record type
template <typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to SQLite DB
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to DB: " + db_path);
  }
  auto& conn = conn_res.value();

  // Insert all records of type T
  auto res = sqlgen::insert_range<T>(records)(conn);
  if (!res) {
    throw std::runtime_error("Insert failed for table " + table_name);
  }
}

// Modify a single column by primary key (record_id as string for genericity)
inline void modify_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id,
                                     const std::string& col_name,
                                     const std::string& new_value) {
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to DB: " + db_path);
  }
  auto& conn = conn_res.value();

  // Dispatch based on table name
  with_table_type(table_name, [&](auto template_tag) {
    using T = decltype(template_tag)::type; // not actually used, workaround below
  });

  // Because sqlgen requires compile-time type information, we handle each table
  // explicitly. The primary key type is:
  // Student:  SNo   -> sqlgen::Varchar<10>  (underlying std::string)
  // Course:   CID   -> uint32_t (auto_incr)
  // Score:    ScID  -> uint32_t (auto_incr)
  // Major:    MID   -> uint32_t

  const auto& n = normalize_table_name(table_name);

  if (n == "Student" || n == "student") {
    // SNo is string primary key
    const auto id = record_id;
    const auto val = new_value;

    const auto res =
        (sqlgen::update<Student> |
         set(col_name.c_str(), val) |
         where("SNo"_c == id))(conn);
    if (!res) {
      throw std::runtime_error("Update failed for table Student");
    }
  } else if (n == "Course" || n == "course") {
    const auto id = static_cast<uint32_t>(std::stoul(record_id));
    const auto val = new_value;

    const auto res =
        (sqlgen::update<Course> |
         set(col_name.c_str(), val) |
         where("CID"_c == id))(conn);
    if (!res) {
      throw std::runtime_error("Update failed for table Course");
    }
  } else if (n == "Score" || n == "score") {
    const auto id = static_cast<uint32_t>(std::stoul(record_id));
    const auto val = new_value;

    const auto res =
        (sqlgen::update<Score> |
         set(col_name.c_str(), val) |
         where("ScID"_c == id))(conn);
    if (!res) {
      throw std::runtime_error("Update failed for table Score");
    }
  } else if (n == "Major" || n == "major") {
    const auto id = static_cast<uint32_t>(std::stoul(record_id));
    const auto val = new_value;

    const auto res =
        (sqlgen::update<Major> |
         set(col_name.c_str(), val) |
         where("MID"_c == id))(conn);
    if (!res) {
      throw std::runtime_error("Update failed for table Major");
    }
  } else {
    throw std::runtime_error("Unknown table name: " + table_name);
  }
}

// Delete by primary key (record_id as string, will be converted as needed)
inline void delete_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id) {
  auto conn_res = sqlgen::sqlite::connect(db_path);
