```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database "test_db.sqlite"
  auto conn_res = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }
  auto conn = std::move(*conn_res);

  // Drop existing Product table if it exists
  auto drop_res =
      conn.and_then(drop_table<Product> | if_exists);
  if (!drop_res) {
    return false;
  }
  conn = std::move(*drop_res);

  // Create Product table
  auto create_res =
      conn.and_then(create_table<Product>);
  if (!create_res) {
    return false;
  }
  conn = std::move(*create_res);

  // Begin transaction
  auto tx_res = conn.and_then(begin_transaction);
  if (!tx_res) {
    return false;
  }
  conn = std::move(*tx_res);

  // Insert all products in a batch
  auto insert_res = conn.and_then(insert_range(products));
  if (!insert_res) {
    // Rollback on failure
    conn.and_then(rollback_transaction);
    return false;
  }
  conn = std::move(*insert_res);

  // Commit transaction
  auto commit_res = conn.and_then(commit_transaction);
  if (!commit_res) {
    return false;
  }

  return true;
}

}  // namespace batch_insert_products
