```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open SQLite connection to "test_db.sqlite"
  sqlite::connection conn{"test_db.sqlite"};

  // Start a transaction (RAII – will roll back on destruction if not committed)
  sqlite::transaction tx{conn};

  // Build the delete operation using sqlgen
  //
  // Equivalent SQL:
  //   DELETE FROM "User"
  //   WHERE "last_login" < DATE('2025-01-01');
  const auto op =
      sqlgen::remove<User> | where("last_login"_c < sqlgen::raw("DATE('2025-01-01')"));

  // Execute the delete and get number of affected rows
  const auto deleted_count = sqlite::execute(conn, op);

  // Commit the transaction
  tx.commit();

  // Return the operation result of commit: here we return the number of deleted rows
  return static_cast<int>(deleted_count);
}

} // namespace delete_inactive_users
```

