#pragma once

#include <filesystem>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  // Student table:
  // SNo      varchar(10) NOT NULL PRIMARY KEY
  // SName    varchar(30) NOT NULL
  // Sex      int NULL DEFAULT 1
  // Birthday datetime NULL
  // Major    int NULL
  // Scorses  float NULL DEFAULT 0
  // Remark   text NULL
  struct Student {
    // Primary key
    sqlgen::PrimaryKey<std::string> SNo;

    std::string SName;
    // Use std::optional for NULLable; default values will be set via raw SQL.
    std::optional<int> Sex;
    std::optional<std::string> Birthday;  // stored as TEXT (datetime)
    std::optional<int> Major;
    std::optional<double> Scorses;
    std::optional<std::string> Remark;
  };

  // Course table:
  // CID    int NOT NULL auto_increment PK
  // CName  varchar(30) NOT NULL
  // Term   int NULL DEFAULT 1
  // CTime  int NULL
  // Credit float NOT NULL DEFAULT 0
  struct Course {
    // AUTOINCREMENT primary key in SQLite
    sqlgen::AutoPrimaryKey<int64_t> CID;

    std::string CName;
    std::optional<int> Term;
    std::optional<int> CTime;
    double Credit;  // NOT NULL
  };

  // Score table:
  // SNo   varchar(10) NOT NULL  (FK -> Student.SNo)
  // CID   int NOT NULL          (FK -> Course.CID)
  // Score float NULL
  // PRIMARY KEY (SNo, CID)
  //
  // Since sqlgen does not have a dedicated composite-primary-key wrapper,
  // we model the fields normally and then add the composite PK via raw SQL.
  struct Score {
    std::string SNo;
    int64_t CID;
    std::optional<double> Score;
  };

  inline void design_eas_database() {
    // Path to the SQLite database file.
    const std::filesystem::path db_path{"test_db.sqlite"};

    // Open / create the SQLite database connection
    sqlgen::sqlite::Connection conn(db_path.string());

    // Create the three tables with sqlgen (basic columns & simple PKs),
    // then adjust them with raw SQL to match the exact specification.

    // 1. Create Student table via sqlgen
    sqlgen::sqlite::create_table<Student>(conn, "Student");

    // 2. Create Course table via sqlgen
    sqlgen::sqlite::create_table<Course>(conn, "Course");

    // 3. Create Score table via sqlgen (without constraints)
    sqlgen::sqlite::create_table<Score>(conn, "Score");

    // Now enforce the exact schema requirements using raw SQL.
    // For idempotency, use IF NOT EXISTS and recreate only what we need.

    // Student table: enforce types & defaults
    conn.exec(R"SQL(
      CREATE TABLE IF NOT EXISTS Student (
        SNo      TEXT PRIMARY KEY NOT NULL,
        SName    TEXT NOT NULL,
        Sex      INTEGER DEFAULT 1,
        Birthday TEXT,
        Major    INTEGER,
        Scorses  REAL DEFAULT 0,
        Remark   TEXT
      );
    )SQL");

    // Course table: AUTOINCREMENT primary key and defaults
    conn.exec(R"SQL(
      CREATE TABLE IF NOT EXISTS Course (
        CID     INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL,
        CName   TEXT NOT NULL,
        Term    INTEGER DEFAULT 1,
        CTime   INTEGER,
        Credit  REAL NOT NULL DEFAULT 0
      );
    )SQL");

    // Score table: composite primary key and foreign keys
    conn.exec(R"SQL(
      CREATE TABLE IF NOT EXISTS Score (
        SNo    TEXT NOT NULL,
        CID    INTEGER NOT NULL,
        Score  REAL,
        PRIMARY KEY (SNo, CID),
        FOREIGN KEY (SNo) REFERENCES Student(SNo),
        FOREIGN KEY (CID) REFERENCES Course(CID)
      );
    )SQL");
  }

}
