  std::string visit_date;
  int total_visits;
  int unique_pages;
};

/**
 * Function: Calculate daily traffic metrics from a log table.
 * 
 * @return List of daily traffic metrics
 */
std::vector<DailyTraffic> query_daily_traffic_metrics() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlite::Connection{"test_db.sqlite"};

  // Make sure the PageVisit table exists (no-op if already created)
  conn.create_table_if_not_exists<PageVisit>();

  // Create a view that matches the required daily aggregation query.
  // This mirrors:
  // SELECT strftime('%Y-%m-%d', visit_time) AS visit_date,
  //        COUNT(*) AS total_visits,
  //        COUNT(DISTINCT url) AS unique_pages
  // FROM PageVisit
  // GROUP BY visit_date
  // ORDER BY visit_date;
  conn.create_view_as<DailyTrafficView>(
      "SELECT "
      "strftime('%Y-%m-%d', visit_time) AS visit_date, "
      "COUNT(*) AS total_visits, "
      "COUNT(DISTINCT url) AS unique_pages "
      "FROM PageVisit "
      "GROUP BY visit_date "
      "ORDER BY visit_date");

  // Query the view and map rows into DailyTrafficView structures
  const auto view_rows = conn.select<DailyTrafficView>();

  // Convert to the public DailyTraffic DTO
  std::vector<DailyTraffic> result;
  result.reserve(view_rows.size());
  for (const auto& row : view_rows) {
    result.push_back(DailyTraffic{
        .visit_date = row.visit_date,
        .total_visits = row.total_visits,
        .unique_pages = row.unique_pages,
    });
  }

  return result;
}

}  // namespace query_daily_traffic_metrics
