```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_product_sales_report {

struct Product {
  static constexpr const char* tablename = "Product";

  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  static constexpr const char* tablename = "Sale";

  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* viewname = "ProductSalesReport";
  static constexpr bool is_view = true;

  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open SQLite database "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Build view definition:
  // SELECT p.category, SUM(s.quantity) AS total_qty, SUM(s.amount) AS total_amt
  // FROM Product p
  // INNER JOIN Sale s ON p.product_id = s.product_id
  // GROUP BY p.category
  // HAVING total_amt > 5000;
  //
  // Note: HAVING uses the aggregate expression directly in sqlgen.
  const auto view_query =
      (select("category"_c,
              sum("quantity"_c).as("total_qty"),
              sum("amount"_c).as("total_amt")) |
       from<Product, Sale>() |
       where("Product.product_id"_c == "Sale.product_id"_c) |
       group_by("category"_c) |
       having(sum("amount"_c) > 5000));

  // Create or replace the view in SQLite
  sqlgen::sqlite::create_view_as<ProductSalesReport>(conn, view_query);

  // Now read from the view and map to ProductSalesReport structures
  const auto read_query = sqlgen::read<std::vector<ProductSalesReport>>;

  const auto reports_from_view =
      sqlgen::sqlite::execute(conn, read_query);

  // Convert to the requested return type CategoryReport
  std::vector<CategoryReport> result;
  result.reserve(reports_from_view.size());
  for (const auto& r : reports_from_view) {
    result.push_back(CategoryReport{
        .category = r.category,
        .total_qty = r.total_qty,
        .total_amt = r.total_amt});
  }

  return result;
}

}  // namespace query_product_sales_report
