```cpp
#pragma once

#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Ensure the Book table exists (no-op if it already exists)
  conn = conn.and_then(create_table<Book> | if_not_exists);

  // Start with a base SELECT query
  auto q = select_from<Book>();

  // Dynamically add WHERE clauses based on provided filters
  if (filters.title_keyword.has_value()) {
    const std::string pattern = "%" + *filters.title_keyword + "%";
    q = q.where(&Book::title, like(pattern));
  }

  if (filters.min_year.has_value()) {
    q = q.where(&Book::year, ge(*filters.min_year));
  }

  if (filters.genre.has_value()) {
    q = q.where(&Book::genre, eq(*filters.genre));
  }

  if (filters.max_price.has_value()) {
    q = q.where(&Book::price, le(*filters.max_price));
  }

  // Execute query and return results as a vector<Book>
  return conn.and_then(q).and_then(read<std::vector<Book>>);
}

}  // namespace query_search_books_by_criteria
