  // INTEGER PRIMARY KEY AUTOINCREMENT
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> user_id;

  // VARCHAR(50) NOT NULL UNIQUE
  sqlgen::NotNull<sqlgen::Unique<sqlgen::VarChar<50>>> username;

  // VARCHAR(100) NOT NULL UNIQUE
  sqlgen::NotNull<sqlgen::Unique<sqlgen::VarChar<100>>> email;

  // age INTEGER CHECK(age >= 18)
  sqlgen::Check<int> age;

  // bio TEXT
  std::string bio;

  // created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  sqlgen::Default<sqlgen::DateTime> created_at;

  // is_verified BOOLEAN DEFAULT FALSE (stored as INTEGER 0)
  sqlgen::Default<bool> is_verified;
};

/**
 * Function: Create a table with various constraints and data types.
 * 
 * @return true if creation succeeds, false otherwise
 */
bool create_complex_table() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  // Build a CREATE TABLE statement with constraints.
