  // We start from the default table definition inferred from UserProfile,
  // then override the columns that require explicit constraints.
  auto stmt =
      create_table<UserProfile> |
      // username VARCHAR(50) NOT NULL UNIQUE
      override_column<&UserProfile::username>(
          column<"username">(varchar<50>, not_null, unique)) |
      // email VARCHAR(100) NOT NULL UNIQUE
      override_column<&UserProfile::email>(
          column<"email">(varchar<100>, not_null, unique)) |
      // age INTEGER CHECK(age >= 18)
      override_column<&UserProfile::age>(
          column<"age">(integer, check("age >= 18"))) |
      // created_at DATETIME DEFAULT CURRENT_TIMESTAMP
      override_column<&UserProfile::created_at>(
          column<"created_at">(datetime, default_("CURRENT_TIMESTAMP"))) |
      // is_verified BOOLEAN DEFAULT 0 (false)
      override_column<&UserProfile::is_verified>(
          column<"is_verified">(boolean, default_(0))) |
      if_not_exists;

  auto res = conn->and_then(stmt);
  return static_cast<bool>(res);
}

