namespace schema_create_trigger_audit_log {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int stock;
};

struct AuditLog {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> log_id;
  std::string table_name;
  int record_id;
  std::string action;
  sqlgen::DateTime timestamp;
};

/**
 * Function: Create a trigger for auditing changes on Product table.
 *
 * Connects to "test_db.sqlite", ensures Product and AuditLog tables exist,
 * and executes raw SQL to create the audit trigger.
 *
 * @return true if trigger creation succeeds, false otherwise
 */
bool create_trigger_audit_log() {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }
  auto conn = std::move(*conn_res);

  // Ensure tables exist (as per assumption they should, but this is safe)
  auto res = conn
      .and_then(create_table<Product> | if_not_exists)
      .and_then(create_table<AuditLog> | if_not_exists);
  if (!res) {
    return false;
  }

  // Raw SQL for creating the trigger
  const char* trigger_sql = R"sql(
CREATE TRIGGER IF NOT EXISTS audit_product_update
AFTER UPDATE ON Product
BEGIN
    INSERT INTO AuditLog (table_name, record_id, action, timestamp)
    VALUES ('Product', OLD.product_id, 'UPDATE', CURRENT_TIMESTAMP);
END;
)sql";

  // Execute the raw SQL using exec
  auto trig_res = res->exec(trigger_sql);
  if (!trig_res) {
    return false;
  }

  return true;
}

}  // namespace schema_create_trigger_audit_log
