 * @return true if migration succeeds, false otherwise
 */
bool migration_add_column() {
  using namespace sqlgen;

  // Connect to the specific SQLite database file.
  // If the project has a different way to pass the filename, adapt this call.
  auto conn_result = sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto& conn = *conn_result;

  // Helper lambda to run a statement and treat "duplicate column" as success.
  auto run_alter = [&](const std::string& sql) -> bool {
    auto exec_res = conn.exec(sql);
    if (exec_res) {
      return true;
    }

    // If execution failed, check if it is because the column already exists.
    // SQLite reports this as "duplicate column name: <col>".
    const auto& err = exec_res.error();
    if (err.find("duplicate column name") != std::string::npos) {
      // Column already exists -> treat as non-fatal.
      return true;
    }

    // Any other error is considered fatal.
    return false;
  };

