```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  if (ids.empty()) {
    // Nothing to delete, treat as success.
    return true;
  }

  // Connect to the specific SQLite database file.
  auto conn_res = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }
  auto conn = std::move(conn_res).value();

  // We’ll perform the soft delete in a transaction to ensure atomicity.
  auto tx_res = conn.transaction();
  if (!tx_res) {
    return false;
  }
  auto tx = std::move(tx_res).value();

  // sqlgen doesn't support a dynamic-sized IN clause directly in its
  // expression system, so we iterate in a transaction and update
  // each Document individually. This still results in a single
  // atomic operation at the database level.
  for (int id : ids) {
    Document doc;
    doc.doc_id = id;
    doc.is_deleted = 1;
    // Use CURRENT_TIMESTAMP from SQLite; we don't set deleted_at here
    // directly so the DB can populate it. We issue a raw UPDATE query.

    // Build and execute:
    // UPDATE Document
    // SET is_deleted = 1, deleted_at = CURRENT_TIMESTAMP
    // WHERE doc_id = ?;
    auto res = tx.execute(
        "UPDATE Document "
        "SET is_deleted = 1, deleted_at = CURRENT_TIMESTAMP "
        "WHERE doc_id = ?;",
        id);

    if (!res) {
      tx.rollback();
      return false;
    }
  }

  // Commit the transaction when all updates succeed.
  auto commit_res = tx.commit();
  if (!commit_res) {
    return false;
  }

  return true;
}

}  // namespace soft_delete_records
