```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  if (amount <= 0.0) {
    return false;
  }

  // Connect to the SQLite database "test_db.sqlite"
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }
  auto conn = std::move(*conn_res);

  // Start a transaction
  auto tx_res = conn.begin_transaction();
  if (!tx_res) {
    return false;
  }
  auto tx = std::move(*tx_res);

  // Step 1: Check if from_account has balance >= amount
  double from_balance = 0.0;
  {
    auto bal_res =
        tx.and_then(select(&Account::balance)
                        .from<Account>()
                        .where(&Account::account_id == from_account_id))
            .and_then(read<std::optional<double>>);
    if (!bal_res || !*bal_res) {
      tx.rollback();
      return false;
    }
    from_balance = **bal_res;
    if (from_balance < amount) {
      tx.rollback();
      return false;
    }
  }

  // Step 2: Deduct from sender (with balance >= amount guard)
  {
    auto upd_res = tx.execute(
        "UPDATE Account SET balance = balance - ? "
        "WHERE account_id = ? AND balance >= ?",
        amount, from_account_id, amount);
    if (!upd_res) {
      tx.rollback();
      return false;
    }
    if (upd_res->changes() != 1) {
      tx.rollback();
      return false;
    }
  }

  // Step 3: Add to receiver
  {
    auto upd_res = tx.execute(
        "UPDATE Account SET balance = balance + ? "
        "WHERE account_id = ?",
        amount, to_account_id);
    if (!upd_res) {
      tx.rollback();
      return false;
    }
    if (upd_res->changes() != 1) {
      tx.rollback();
      return false;
    }
  }

  // Commit transaction
  if (!tx.commit()) {
    tx.rollback();
    return false;
  }

  return true;
}

}  // namespace transaction_transfer_funds
```

