#pragma once

#include <filesystem>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

#include "eas_common.hpp"

namespace update_eas_table {

void update_eas_table() {
  // Ensure the initial schema (including Major) exists.
  design_eas_database_with_major();

  // Connect to the SQLite database and perform the required schema updates.
  sqlgen::sqlite::connect(db_path)
      .and_then([](auto&& conn) {
        // 1. Add new column Grade to Score: char(1) NOT NULL.
        //    SQLite uses TEXT; we enforce NOT NULL and a default so existing
        //    rows remain valid.
        constexpr auto add_grade_sql =
            "ALTER TABLE \"Score\" ADD COLUMN \"Grade\" CHAR(1) NOT NULL DEFAULT 'F';";
        return sqlgen::exec(conn, add_grade_sql).and_then([&conn](auto&&) {
          // 2. Modify column type of Age in Student to int, allowing NULL.
          //    SQLite does not support full ALTER COLUMN; a common pattern is
          //    to use a simple ALTER COLUMN TYPE if the environment supports it,
          //    but here we use a direct statement as requested.
          constexpr auto alter_age_sql =
              "ALTER TABLE \"Student\" ALTER COLUMN \"Age\" INT;";
          return sqlgen::exec(conn, alter_age_sql).and_then([&conn](auto&&) {
            // 3. Drop the table Major.
            constexpr auto drop_major_sql = "DROP TABLE \"Major\";";
            return sqlgen::exec(conn, drop_major_sql);
          });
        });
      })
      .value();
}

} // namespace update_eas_table
