#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_order_status {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string status;
  sqlgen::DateTime order_date;
  double total_amount;
};

int update_order_status() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open (or create) SQLite database
  sqlite::Database db{"test_db.sqlite"};

  // Make sure the mapping for Order is known to sqlgen (if required elsewhere)
  // This call is harmless if the table already exists.
  db.sync_schema<Order>("Order");

  // 1) Expire 'pending' orders older than 7 days
  auto stmt_expire =
      db.prepare(R"(UPDATE "Order"
                    SET status = 'expired'
                    WHERE status = 'pending'
                      AND order_date < DATE('now', '-7 days');)");
  const auto expired_count = stmt_expire.execute();

  // 2) Simulate delivery confirmation and update 'shipped' -> 'delivered'
  //    For this example we simply update all 'shipped' orders.
  auto stmt_deliver =
      db.prepare(R"(UPDATE "Order"
                    SET status = 'delivered'
                    WHERE status = 'shipped';)");
  const auto delivered_count = stmt_deliver.execute();

  // Return total number of affected rows
  return static_cast<int>(expired_count + delivered_count);
}

} // namespace update_order_status
