namespace upsert_user_profile {

TEST(sqlite, upsert_user_profile) {
  using namespace sqlgen;
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<UserProfile>(conn);
  create_table<UserProfile>(conn);

  UserProfile u1{.user_id = 1, .bio = "first", .avatar_url = "a1.png"};
  ASSERT_TRUE(upsert_user_profile(u1));
  auto rows1 = sqlgen::read<std::vector<UserProfile>>(conn).value();
  ASSERT_EQ(rows1.size(), 1u);
  EXPECT_EQ(rows1[0].bio.value(), "first");

