  sqlgen::PrimaryKey<int> user_id;
  std::optional<std::string> bio;
  std::optional<std::string> avatar_url;
};

bool upsert_user_profile(const UserProfile& u) {
  using namespace sqlgen;

  // Connect to the specific SQLite database file.
  // If the library's default connect() opens an in-memory DB, we use the
  // filename overload provided by sqlgen::sqlite.
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }
  auto& conn = *conn_res;

  // We assume a table named "UserProfile" with columns:
  //   user_id (PRIMARY KEY), bio, avatar_url
  //
  // Implement classic "try insert, if fails then update" logic, because
  // sqlgen does not expose a direct "INSERT OR REPLACE" shortcut in the
  // provided snippets.

  // First, try an INSERT.
  {
    // sqlgen::execute returns something like expected<void, error>.
    // We use raw SQL with placeholders and rely on sqlite parameter
    // binding via sqlgen.
    auto insert_res = conn.execute(
        "INSERT INTO UserProfile (user_id, bio, avatar_url) "
        "VALUES (?, ?, ?);",
        u.user_id.value,  // unwrap PrimaryKey
        u.bio,
        u.avatar_url);

    if (insert_res) {
      // Insert succeeded.
      return true;
    }

    // If insertion failed for a reason other than PK conflict, we don't
    // attempt an UPDATE, and just signal failure.
    // The specific error code classification is library/SQLite-specific;
    // since we don't have direct access here, we optimistically proceed
    // to UPDATE and rely on its success/failure instead.
  }

  // Either the row already exists (PK conflict) or the INSERT failed for
  // some other reason. Try an UPDATE on the existing row.
  auto update_res = conn.execute(
      "UPDATE UserProfile "
      "SET bio = ?, avatar_url = ? "
      "WHERE user_id = ?;",
      u.bio,
      u.avatar_url,
      u.user_id.value);

  if (!update_res) {
    return false;
  }

  // Some sqlgen backends may expose the number of affected rows, but that
  // detail is not available in the given snippets. We treat a successful
  // execute as success for the upsert.
  return true;
}

} // namespace upsert_user_profile
