/**
 * Function: Create a view SalesSummary that aggregates sales by product.
 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  // Ensure the underlying tables exist.
  // Note: Product and Sale are assumed to exist, but we create them
  // with IF NOT EXISTS for robustness / idempotency.
  conn = std::move(conn)
             .and_then(create_table<Product> | if_not_exists)
             .and_then(create_table<Sale> | if_not_exists);
  if (!conn) {
    return false;
  }

  // Manually drop the view if it already exists (SQLite-specific)
  {
    auto dropped = conn->exec(
        "DROP VIEW IF EXISTS SalesSummary;"
    );
    if (!dropped) {
      return false;
    }
  }

  // Construct the SELECT query that defines the view.
  //
  // Equivalent to:
  // SELECT p.name as product_name,
  //        SUM(s.quantity) as total_quantity,
  //        SUM(s.amount) as total_revenue
  // FROM Sale s
  // JOIN Product p ON s.product_id = p.product_id
  // GROUP BY p.name;
  //
  // Using sqlgen query builders:
  auto select_query =
      select(
          (column<&Product::name>()       | as<"product_name">),
          (sum(column<&Sale::quantity>()) | as<"total_quantity">),
          (sum(column<&Sale::amount>())   | as<"total_revenue">))
          .from<Sale>()
          .join<Product>(
              on(column<&Sale::product_id>() == column<&Product::product_id>()))
          .group_by(column<&Product::name>());

  // Create the view using CREATE VIEW AS <select_query>
  auto result =
      std::move(conn)
          .and_then(create_view_as<SalesSummary>(select_query));

  return static_cast<bool>(result);
}

