```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlite::connect("test_db.sqlite");

  // sqlgen focuses on SELECT with implicit joins based on the mapped structs
  // and does not provide an explicit RIGHT JOIN operator, while SQLite itself
  // does not support RIGHT JOIN natively.
  //
  // To *include all departments*, we conceptually want:
  //
  //   SELECT Department.name, Project.name
  //   FROM Project
  //   RIGHT JOIN Department
  //     ON Project.department_id = Department.department_id;
  //
  // Because SQLite has only LEFT JOIN, the usual workaround is to rewrite the
  // RIGHT JOIN as a LEFT JOIN with the table order swapped:
  //
  //   SELECT Department.name, Project.name
  //   FROM Department
  //   LEFT JOIN Project
  //     ON Department.department_id = Project.department_id;
  //
  // sqlgen does not (as of the referenced tests) expose a high‑level join API
  // that can directly perform this and map the joined rows into a custom
  // result type. Therefore we fall back to a small, direct SQL query executed
  // via the underlying sqlite connection handle, while still returning a
  // std::vector<DepProj> as specified.

  std::vector<DepProj> result;

  // Access raw sqlite3* from sqlgen connection.
  // The sqlgen::sqlite::connection type exposes a handle() returning sqlite3*.
  auto* raw = conn.handle();

  const char* sql = R"SQL(
    SELECT d.name AS department_name,
           p.name AS project_name
    FROM Department d
    LEFT JOIN Project p
      ON d.department_id = p.department_id
    ORDER BY d.department_id, p.project_id
  )SQL";

  sqlite3_stmt* stmt = nullptr;
  if (sqlite3_prepare_v2(raw, sql, -1, &stmt, nullptr) != SQLITE_OK) {
    // On error, return empty vector
    return result;
  }

  while (sqlite3_step(stmt) == SQLITE_ROW) {
    DepProj row;

    // department_name (can be NULL)
    if (sqlite3_column_type(stmt, 0) == SQLITE_NULL) {
      row.department_name = std::nullopt;
    } else {
      const unsigned char* txt =
          sqlite3_column_text(stmt, 0);  // department_name
      row.department_name = txt ? reinterpret_cast<const char*>(txt) : "";
    }

    // project_name (may be NULL when no project; we map NULL -> empty string)
    if (sqlite3_column_type(stmt, 1) == SQLITE_NULL) {
      row.project_name = "";
    } else {
      const unsigned char* txt =
          sqlite3_column_text(stmt, 1);  // project_name
      row.project_name = txt ? reinterpret_cast<const char*>(txt) : "";
    }

    result.push_back(std::move(row));
  }

  sqlite3_finalize(stmt);

  return result;
}

}  // namespace right_join_departments_projects
```

