#include <vector>
#include <optional>
#include <string>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Connects to the SQLite database "test_db.sqlite", ensures the Event table
 * exists, inserts the provided events, runs a query to extract date/time
 * parts and compute duration, and returns the results as a vector of
 * TemporalAnalysis.
 *
 * The analysis includes:
 *  - Individual date/time components
 *  - Weekday information
 *  - Unix epoch conversion
 *  - Day-level duration between start and end times (when end_time is not null)
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Connect to the SQLite database "test_db.sqlite"
  auto connection = Connection{"test_db.sqlite"};

  // Ensure the Event table exists with the appropriate schema
  {
    const auto create_stmt = CreateTable<Event>{};
    connection.execute(create_stmt);
  }

  // Insert the provided events into the Event table
  if (!events.empty()) {
    const auto insert_stmt = Insert<Event>{events};
    connection.execute(insert_stmt);
  }

  // Build the SQL for temporal analysis, matching the requested operations.
  //
  // SQLite does not provide DAY/MONTH/YEAR/HOUR/MINUTE/SECOND/WEEKDAY/DAYS_BETWEEN
  // as functions exactly like in the reference SQL, so we use strftime,
  // julianday, unixepoch, etc., and alias them to match the requested semantics.
  //
  // - Day, month, year, hour, minute, second: strftime('%d'/'%m'/'%Y'/'%H'/'%M'/'%S', ...)
  // - Weekday: SQLite's '%w' returns 0=Sunday..6=Saturday; to emulate a
  //   Monday-based 0..6 like many WEEKDAY() definitions, use (strftime('%w') + 6) % 7.
  // - Unix epoch: unixepoch()
  // - Duration in days: (julianday(end_time) - julianday(start_time))
  //
  // Only events with non-null end_time are returned, as requested.
  const std::string temporal_query_sql =
      "SELECT "
      "  event_id, "
      "  event_name, "
      "  CAST(strftime('%d', start_time) AS INTEGER) AS start_day, "
      "  CAST(strftime('%m', start_time) AS INTEGER) AS start_month, "
      "  CAST(strftime('%Y', start_time) AS INTEGER) AS start_year, "
      "  CAST(strftime('%H', start_time) AS INTEGER) AS start_hour, "
      "  CAST(strftime('%M', start_time) AS INTEGER) AS start_minute, "
      "  CAST(strftime('%S', start_time) AS INTEGER) AS start_second, "
      "  CAST((CAST(strftime('%w', start_time) AS INTEGER) + 6) % 7 AS INTEGER) AS start_weekday, "
      "  CAST(unixepoch(start_time) AS INTEGER) AS start_epoch, "
      "  (julianday(end_time) - julianday(start_time)) AS duration_days "
      "FROM Event "
      "WHERE end_time IS NOT NULL;";

  // Execute the custom SQL and map the result rows into TemporalAnalysis
  std::vector<TemporalAnalysis> results;

  auto stmt = connection.prepare(temporal_query_sql);
  while (stmt.step()) {
    TemporalAnalysis ta{};
    // Column indices correspond to the SELECT list above
    ta.event_id      = stmt.get<int>(0);
    ta.event_name    = stmt.get<std::string>(1);
    ta.start_day     = stmt.get<int>(2);
    ta.start_month   = stmt.get<int>(3);
    ta.start_year    = stmt.get<int>(4);
    ta.start_hour    = stmt.get<int>(5);
    ta.start_minute  = stmt.get<int>(6);
    ta.start_second  = stmt.get<int>(7);
    ta.start_weekday = stmt.get<int>(8);
    ta.start_epoch   = stmt.get<int64_t>(9);

    // duration_days may be NULL if something is off, so check for null.
    if (stmt.is_null(10)) {
      ta.duration_days = std::nullopt;
    } else {
      ta.duration_days = stmt.get<double>(10);
    }

    results.emplace_back(std::move(ta));
  }

  return results;
}

}  // namespace analyze_temporal_data
