namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  // and make sure the Inventory table exists.
  auto result =
      sqlgen::sqlite::connect("test_db.sqlite")
          // Ensure table exists with the expected schema
          .and_then(create_table<Inventory> | if_not_exists)
          // Perform upsert (insert OR replace) for the provided items
          .and_then(write(items, insert_or_replace))
          // Read back all rows from Inventory to verify behavior
          .and_then(sqlgen::read<std::vector<Inventory>>);

  if (!result) {
    // Connection or query failed.
    return false;
  }

  const auto& stored_items = *result;

  // Basic verification: we expect at least as many rows as items we attempted
  // to upsert (could be more if table was not empty beforehand).
  if (stored_items.size() < items.size()) {
    return false;
  }

  // Verify that for each input item there's a matching row in the database
  // with same primary key and fields.
  for (const auto& input_item : items) {
    const auto it = std::find_if(
        stored_items.begin(), stored_items.end(),
        [&](const Inventory& db_item) {
          return db_item.item_id == input_item.item_id;
        });

    if (it == stored_items.end()) {
      return false;
    }

    if (it->name != input_item.name || it->quantity != input_item.quantity) {
      return false;
    }
  }

  return true;
}

}  // namespace upsert_inventory_items
