#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  // Minimal subset of fields; the real DB table will have more columns.
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating SQL tables for User and Friendship
 * in the SQLite database "test_db.sqlite", inserting the provided rows, and
 * then running several analysis queries:
 *
 * 1. SELF-JOIN to find mutual friends.
 * 2. Nested query to find users with more than N friends.
 * 3. Friend-of-friend relationships (exactly one mutual friend).
 * 4. Aggregation of friends per user.
 * 5. Users in the same city who are not yet friends (recommendations).
 *
 * This function currently returns the list of mutual-friend user pairs
 * (user1_name, user2_name) as FriendConnection.
 */
std::vector<FriendConnection> analyze_social_network_impl(
    const std::vector<User>& users,
    const std::vector<Friendship>& friendships) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database "test_db.sqlite"
  auto conn = sqlite::Connection{"test_db.sqlite"};

  // ---------------------------------------------------------------------------
  // 1. Create tables for User and Friendship
  // ---------------------------------------------------------------------------
  // We explicitly create the tables with the schema described in the prompt,
  // rather than relying on reflection from the C++ structs, so that we can
  // include all required columns (email, join_date, city, etc.).
  {
    const char* create_user_sql =
        R"(CREATE TABLE IF NOT EXISTS "User" (
             "user_id"    INTEGER PRIMARY KEY,
             "username"   TEXT NOT NULL UNIQUE,
             "email"      TEXT NOT NULL UNIQUE,
             "join_date"  DATETIME NOT NULL,
             "city"       TEXT
           );)";

    const char* create_friendship_sql =
        R"(CREATE TABLE IF NOT EXISTS "Friendship" (
             "user_id1"        INTEGER NOT NULL,
             "user_id2"        INTEGER NOT NULL,
             "friendship_date" DATETIME NOT NULL,
             PRIMARY KEY ("user_id1", "user_id2"),
             FOREIGN KEY ("user_id1") REFERENCES "User"("user_id"),
             FOREIGN KEY ("user_id2") REFERENCES "User"("user_id")
           );)";

    conn.execute(create_user_sql);
    conn.execute(create_friendship_sql);
  }

  // Clear any existing data to make this function deterministic for tests.
  conn.execute(R"(DELETE FROM "Friendship";)");
  conn.execute(R"(DELETE FROM "User";)");

  // ---------------------------------------------------------------------------
  // Insert provided users/friendships into the DB
  // (We only know user_id + username from the C++ struct; we synthesize the
  // remaining columns so that they satisfy NOT NULL constraints.)
  // ---------------------------------------------------------------------------
  {
    // Insert users
    const char* insert_user_sql =
        R"(INSERT INTO "User" ("user_id", "username", "email", "join_date", "city")
           VALUES (?, ?, ?, ?, ?);)";
    auto stmt_user = conn.prepare(insert_user_sql);

    for (const auto& u : users) {
      // Synthetic values for fields not present in the struct
      const std::string email = u.username + "@example.com";
      const std::string join_date = "2020-01-01 00:00:00";
      const std::string city = "Unknown";

      stmt_user.reset();
      stmt_user.bind(1, static_cast<int>(u.user_id.value));
      stmt_user.bind(2, u.username);
      stmt_user.bind(3, email);
      stmt_user.bind(4, join_date);
      stmt_user.bind(5, city);
      stmt_user.step();  // execute
    }

    // Insert friendships
    const char* insert_friendship_sql =
        R"(INSERT INTO "Friendship" ("user_id1", "user_id2", "friendship_date")
           VALUES (?, ?, ?);)";
    auto stmt_friendship = conn.prepare(insert_friendship_sql);

    for (const auto& f : friendships) {
      stmt_friendship.reset();
      stmt_friendship.bind(1, f.user1_id);
      stmt_friendship.bind(2, f.user2_id);
      stmt_friendship.bind(3, std::string{f.created_at.value});
      stmt_friendship.step();  // execute
    }
  }

  // ---------------------------------------------------------------------------
  // 2–5: Run analysis queries. Only the result of (1) is returned, but all
  //      requested patterns are exercised.
  // ---------------------------------------------------------------------------

  // 2. SELF-JOIN to find mutual friends (friends who share the same friend).
  //    We mirror the style of the reference SQL, but ensure it works against
  //    the schema we just created.
  const char* mutual_friends_sql =
      R"(SELECT u1.username AS user1_name,
               u2.username AS user2_name,
               COUNT(DISTINCT f1.user_id2) AS mutual_friends
         FROM "User" u1
         JOIN "Friendship" f1 ON u1.user_id = f1.user_id1
         JOIN "Friendship" f2 ON f1.user_id2 = f2.user_id1
         JOIN "User" u2 ON f2.user_id2 = u2.user_id
         WHERE u1.user_id < u2.user_id
           AND EXISTS (
             SELECT 1
             FROM "Friendship" f3
             WHERE f3.user_id1 = u1.user_id
               AND f3.user_id2 = u2.user_id
           )
         GROUP BY u1.user_id, u2.user_id
         HAVING COUNT(DISTINCT f1.user_id2) > 0;)";
  auto stmt_mutual = conn.prepare(mutual_friends_sql);

  std::vector<FriendConnection> result;

  while (stmt_mutual.step()) {
    FriendConnection conn_rec;
    conn_rec.user1_name = stmt_mutual.column_text(0);
    conn_rec.user2_name = stmt_mutual.column_text(1);
    result.push_back(std::move(conn_rec));
  }

  // 3. Nested query to find users with more than N friends.
  //    Here we choose N = 2 for demonstration (could be parameterized).
  {
    const int N = 2;
    const char* more_than_n_friends_sql =
        R"(SELECT u.user_id, u.username, COUNT(f.user_id2) AS friend_count
           FROM "User" u
           LEFT JOIN "Friendship" f ON u.user_id = f.user_id1
           GROUP BY u.user_id, u.username
           HAVING friend_count > (
             SELECT COUNT(*) FROM "Friendship" f2
             WHERE f2.user_id1 = u.user_id
           ) + ?;)";
    auto stmt_more = conn.prepare(more_than_n_friends_sql);
    stmt_more.bind(1, N);
    while (stmt_more.step()) {
      // We do not need the actual values for the return type; just execute.
      (void)stmt_more.column_int(0);
      (void)stmt_more.column_text(1);
      (void)stmt_more.column_int(2);
    }
  }

  // 4. Friend-of-friend relationships (people connected through exactly one
  //    mutual friend). We only execute this query for side effects / validation.
  {
    const char* fof_sql =
        R"(SELECT DISTINCT u1.username AS user1_name,
                           u3.username AS user2_name
           FROM "Friendship" f1
           JOIN "Friendship" f2
             ON f1.user_id2 = f2.user_id1
           JOIN "User" u1 ON u1.user_id = f1.user_id1
           JOIN "User" u3 ON u3.user_id = f2.user_id2
           WHERE u1.user_id <> u3.user_id
             AND NOT EXISTS (
               SELECT 1
               FROM "Friendship" direct
               WHERE direct.user_id1 = u1.user_id
                 AND direct.user_id2 = u3.user_id
             )
           GROUP BY u1.user_id, u3.user_id
           HAVING COUNT(DISTINCT f1.user_id2) = 1;)";
    auto stmt_fof = conn.prepare(fof_sql);
    while (stmt_fof.step()) {
      (void)stmt_fof.column_text(0);
      (void)stmt_fof.column_text(1);
    }
  }

  // 5. Count friends per user and identify most connected users (aggregation).
  {
    const char* most_connected_sql =
        R"(WITH friend_counts AS (
             SELECT f.user_id1 AS user_id,
                    COUNT(f.user_id2) AS friend_count
             FROM "Friendship" f
             GROUP BY f.user_id1
           )
           SELECT u.username, fc.friend_count
           FROM friend_counts fc
           JOIN "User" u ON u.user_id = fc.user_id
           WHERE fc.friend_count = (
             SELECT MAX(friend_count) FROM friend_counts
           );)";
    auto stmt_mc = conn.prepare(most_connected_sql);
    while (stmt_mc.step()) {
      (void)stmt_mc.column_text(0);
      (void)stmt_mc.column_int(1);
    }
  }

  // 6. Users in the same city who are not yet friends (recommendations).
  {
    const char* recommendations_sql =
        R"(SELECT u1.username, u2.username
           FROM "User" u1
           JOIN "User" u2
             ON u1.city = u2.city
            AND u1.user_id < u2.user_id
           WHERE NOT EXISTS (
             SELECT 1
             FROM "Friendship" f
             WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
                OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
           );)";
    auto stmt_reco = conn.prepare(recommendations_sql);
    while (stmt_reco.step()) {
      (void)stmt_reco.column_text(0);
      (void)stmt_reco.column_text(1);
    }
  }

  // The function's contract: return FriendConnection records of mutual friends.
  return result;
}

}  // namespace analyze_social_network
