                "You cannot call to<...> twice.");
  return SelectFrom<TableOrQueryType, AliasType, FieldsType, JoinsType,
                    WhereType, GroupByType, OrderByType, LimitType,
                    NewToType>{.fields_ = _s.fields_,
                               .from_ = _s.from_,
