```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace trim_and_length_validation {

struct UserProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  std::string email;
};

struct ValidatedProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string trimmed_name;
  std::string trimmed_email;
  int name_length;
  int email_length;
};

/**
 * description: trim_and_length_validation.
 * This function demonstrates how to trim whitespace from string columns and validate their lengths using sqlgen read API.
 * It returns a vector of ValidatedProfile structs, where each struct contains the user_id, trimmed_name, trimmed_email, name_length, and email_length.
 * Returns: std::vector<ValidatedProfile>.
 */
std::vector<ValidatedProfile> trim_and_length_validation() {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  const auto conn_result = sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    // If connection fails, return an empty result.
    return {};
  }
  const auto& conn = *conn_result;

  // Read all user profiles from the UserProfile table
  const auto profiles_result = read<std::vector<UserProfile>>(conn);
  if (!profiles_result) {
    // If reading fails, return an empty result.
    return {};
  }
  const auto& profiles = *profiles_result;

  // Process each profile: trim whitespace and compute lengths
  std::vector<ValidatedProfile> validated;
  validated.reserve(profiles.size());

  for (const auto& p : profiles) {
    // Use std::string operations to mimic ltrim/rtrim/trim semantics.
    // Leading whitespace
    const auto ltrim_pos = p.name.find_first_not_of(" \t\n\r\f\v");
    // Trailing whitespace
    const auto rtrim_pos = p.name.find_last_not_of(" \t\n\r\f\v");
    std::string trimmed_name;
    if (ltrim_pos == std::string::npos) {
      trimmed_name = "";
    } else {
      trimmed_name = p.name.substr(ltrim_pos, rtrim_pos - ltrim_pos + 1);
    }

    const auto ltrim_email_pos = p.email.find_first_not_of(" \t\n\r\f\v");
    const auto rtrim_email_pos = p.email.find_last_not_of(" \t\n\r\f\v");
    std::string trimmed_email;
    if (ltrim_email_pos == std::string::npos) {
      trimmed_email = "";
    } else {
      trimmed_email =
          p.email.substr(ltrim_email_pos, rtrim_email_pos - ltrim_email_pos + 1);
    }

    // Compute lengths after trimming (equivalent to SQLite length(trim(column)))
    const int name_length = static_cast<int>(trimmed_name.size());
    const int email_length = static_cast<int>(trimmed_email.size());

    validated.push_back(ValidatedProfile{
        .user_id = p.user_id,
        .trimmed_name = trimmed_name,
        .trimmed_email = trimmed_email,
        .name_length = name_length,
        .email_length = email_length,
    });
  }

  return validated;
}

}  // namespace trim_and_length_validation
