/**
 * Calculate per-item order metrics by loading the provided items into the OrderItem
 * table in the SQLite database "test_db.sqlite" and evaluating SQL expressions for
 * totals, discounts, taxes, cost, grouping, and estimated profit.
 *
 * The arithmetic operations demonstrated:
 *  - Multiplication: unit_price * quantity
 *  - Division: discount_rate/100, tax_rate/100, and total / quantity
 *  - Addition/Subtraction: applying discounts and taxes
 *  - Modulo: quantity % 10 for grouping
 *
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return {};
  }
  auto conn = std::move(conn_res.value());

  // Ensure the OrderItem table exists and is empty for this analysis run.
  // create_table<OrderItem> uses the struct definition above.
  auto schema_res =
      (create_table<OrderItem> | if_not_exists)(conn)
          .and_then([&](auto&&) { return sqlite::exec(conn, "DELETE FROM OrderItem;"); });

  if (!schema_res) {
    return {};
  }

  // Insert provided items into OrderItem table
  if (!items.empty()) {
    auto write_res = write(conn, items);
    if (!write_res) {
      return {};
    }
  }

  // Perform the metric calculations via a SELECT with arithmetic expressions.
  // Uses COALESCE to handle nullable discount_rate and tax_rate.
  const char* query =
      "SELECT "
      "  item_id, "
      "  order_id, "
      "  product_id, "
      "  unit_price, "
      "  quantity, "
      "  COALESCE(discount_rate, 0.0) AS discount_rate, "
      "  COALESCE(tax_rate, 0.0) AS tax_rate, "
      "  (unit_price * quantity) AS gross_total, "
      "  (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100.0)) AS discounted_total, "
      "  (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100.0) * "
      "     (1 + COALESCE(tax_rate, 0)/100.0)) AS final_total, "
      // Guard against division by zero for unit_cost
      "  CASE WHEN quantity <> 0 THEN (unit_price * quantity / quantity) "
      "       ELSE 0.0 "
      "  END AS unit_cost, "
      "  (quantity % 10) AS quantity_group, "
      "  (unit_price * 0.3) AS estimated_profit "
      "FROM OrderItem;";

  auto rows_res = sqlite::query<std::vector<detail::OrderMetricsRow>>(conn, query);
  if (!rows_res) {
    return {};
  }

  const auto& rows = rows_res.value();
  std::vector<OrderMetrics> result;
  result.reserve(rows.size());

  for (const auto& r : rows) {
    OrderMetrics m{
        .item_id = r.item_id,
        .order_id = r.order_id,
        .product_id = r.product_id,
        .unit_price = r.unit_price,
        .quantity = r.quantity,
        .discount_rate = r.discount_rate,
        .tax_rate = r.tax_rate,
        .gross_total = r.gross_total,
        .discounted_total = r.discounted_total,
        .final_total = r.final_total,
        .unit_cost = r.unit_cost,
        .quantity_group = r.quantity_group,
        .estimated_profit = r.estimated_profit,
    };
    result.push_back(std::move(m));
  }

  return result;
}

}  // namespace calculate_order_metrics
