 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open connection to the SQLite database "test_db.sqlite"
  auto db = sqlgen::sqlite::Database{"test_db.sqlite"};

  // Build the query:
  // SELECT "Order"."order_id", "Customer"."name" AS customer_name,
  //        "Payment"."amount"
  // FROM "Order"
  // INNER JOIN "Customer" ON "Order"."customer_id" = "Customer"."customer_id"
  // INNER JOIN "Payment" ON "Order"."order_id" = "Payment"."order_id"
  // ORDER BY "Payment"."amount" DESC;
  //
  // Mapped into sqlgen's type-safe query DSL.
  const auto query =
      Select<&Order::order_id, &Customer::name, &Payment::amount>{}
          .from<Order>()
          .join<Customer>(On<&Order::customer_id, &Customer::customer_id>{})
          .join<Payment>(On<&Order::order_id, &Payment::order_id>{})
          .order_by<&Payment::amount>(OrderBy::Desc);

  // Execute and fetch as a vector of Consolidated rows
  auto result = db.fetch_all<Consolidated>(query);

  return result;
}

}  // namespace join_orders_customers_payments
