```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace replace_text_in_notes {

struct Note {
  sqlgen::PrimaryKey<int> note_id;
  std::string content;
};

struct UpdatedNote {
  sqlgen::PrimaryKey<int> note_id;
  std::string updated_content;
};

/**
 * description: replace_text_in_notes.
 * This function demonstrates how to replace text in notes using sqlgen update API.
 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite".
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Ensure the Notes table exists (assumed by the problem statement).
  // If it doesn't, this will create it; otherwise it is a no-op.
  conn
      .and_then(create_table<Note> | if_not_exists)
      .value();  // propagate failure as exception if any

  // 1. Update all Note rows, replacing all occurrences of "foo" with "bar"
  //    in the content field, using SQLite's built-in REPLACE function.
  //
  //    Equivalent SQL:
  //      UPDATE Note
  //      SET content = REPLACE(content, 'foo', 'bar');
  //
  //    In sqlgen:
  conn
      .and_then(
          update<Note>.set("content"_c = func<"REPLACE">("content"_c, val("foo"), val("bar"))))
      .value();

  // 2. Read back the updated rows as UpdatedNote for verification.
  //    We map Note.content into UpdatedNote.updated_content by using a
  //    dynamic select that aliases the content column.
  //
  //    Equivalent SQL:
  //      SELECT note_id, content AS updated_content FROM Note;
  //
  //    In sqlgen:
  const auto updated_notes =
      conn
          .and_then(select<UpdatedNote>(
              from<Note>(),
              "note_id"_c,
              col("content"_c).as<"updated_content">()))
          .value();

  return updated_notes;
}

}  // namespace replace_text_in_notes
