```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace inventory_bulk_write_and_read {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
  std::string location;
};

/**
 * description: inventory_bulk_write_and_read.
 * This function demonstrates how to perform bulk write and read operations on an inventory table.
 * It first drops and recreates the table, then writes the given items to the table.
 * Finally, it reads back the items with quantity > 50, orders them by quantity in descending order,
 * and returns true if at least one item is found.
 * Returns: bool.
 */
bool inventory_bulk_write_and_read(const std::vector<Inventory>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database file "test_db.sqlite"
  const auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // Drop the Inventory table if it exists, then recreate it
  {
    const auto drop_res = sqlgen::execute(
        conn, "DROP TABLE IF EXISTS Inventory");
    if (!drop_res) {
      return false;
    }

    const auto create_res = sqlgen::execute(
        conn,
        "CREATE TABLE IF NOT EXISTS Inventory ("
        "item_id INTEGER PRIMARY KEY,"
        "name VARCHAR(100) NOT NULL,"
        "quantity INTEGER NOT NULL,"
        "location VARCHAR(50)"
        ")");
    if (!create_res) {
      return false;
    }
  }

  // Bulk write / insert the provided items
  {
    const auto write_res = sqlgen::write(conn, items);
    if (!write_res) {
      return false;
    }
  }

  // Read back items where quantity > 50 ordered by quantity DESC
  {
    const auto query_res =
        sqlgen::read<std::vector<Inventory>>(
            conn,
            "SELECT item_id, name, quantity, location "
            "FROM Inventory "
            "WHERE quantity > 50 "
            "ORDER BY quantity DESC");
    if (!query_res) {
      return false;
    }

    const auto& filtered_items = *query_res;
    return !filtered_items.empty();
  }
}

}  // namespace inventory_bulk_write_and_read
