```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // Connect to the SQLite database file "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Ensure foreign key constraints are enforced in SQLite
  conn.execute("PRAGMA foreign_keys = ON;");

  // Drop tables if they already exist to start with a clean slate
  conn.execute("DROP TABLE IF EXISTS Child;");
  conn.execute("DROP TABLE IF EXISTS Parent;");

  // Create Parent and Child tables with the required constraints
  conn.execute(
      "CREATE TABLE Parent ("
      "  parent_id INTEGER PRIMARY KEY,"
      "  name TEXT NOT NULL"
      ");");

  conn.execute(
      "CREATE TABLE Child ("
      "  child_id INTEGER PRIMARY KEY,"
      "  parent_id INTEGER,"
      "  note TEXT,"
      "  FOREIGN KEY(parent_id) REFERENCES Parent(parent_id) ON DELETE CASCADE"
      ");");

  // Insert a parent row
  Parent p{.parent_id = 1, .name = "Parent 1"};
  conn.insert(p);

  // Insert one or more child rows referencing that parent
  Child c1{.child_id = 1, .parent_id = 1, .note = "Child of Parent 1"};
  Child c2{.child_id = 2, .parent_id = 1, .note = "Another Child"};
  conn.insert(c1);
  conn.insert(c2);

  // Delete the parent row
  conn.erase(p);

  // Verify whether the child rows referencing parent_id = 1 were deleted
  auto remaining_children =
      conn.select<Child>().where(sqlgen::column<&Child::parent_id>() == 1).all();

  // If cascade delete worked, there should be no remaining children
  return remaining_children.empty();
}

}  // namespace cascade_delete_demo
```

