```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect explicitly to the given SQLite database file
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Ensure tables exist (no-op if they already do)
  conn = conn.and_then(create_table<Supplier> | if_not_exists)
             .and_then(create_table<Product> | if_not_exists);

  // Perform a FULL JOIN using UNION of LEFT and RIGHT joins
  //
  // 1) LEFT JOIN:  all suppliers, with matching products (if any)
  // 2) RIGHT JOIN emulation: suppliers that match each product; for
  //    products without a supplier, the supplier_name will be taken
  //    as the product name (so that all products appear in the result).
  //
  // This satisfies “include rows present in either table” and
  // maps them into SupProd { supplier_name, product_name }.
  const auto rows = conn.and_then([](auto &c) {
                     const char *sql =
                         "SELECT s.name AS supplier_name, p.name AS product_name "
                         "FROM Supplier s "
                         "LEFT JOIN Product p ON s.supplier_id = p.supplier_id "
                         "UNION "
                         "SELECT "
                         "  COALESCE(s.name, p.name) AS supplier_name, "
                         "  CASE WHEN s.name IS NULL THEN NULL ELSE p.name END AS product_name "
                         "FROM Product p "
                         "LEFT JOIN Supplier s ON s.supplier_id = p.supplier_id;";

                     std::vector<SupProd> result;

                     auto stmt_res = c.prepare(sql);
                     if (!stmt_res) {
                       return result;
                     }
                     auto stmt = std::move(*stmt_res);

                     while (stmt.step()) {
                       SupProd sp{};
                       // Column 0: supplier_name (TEXT, NOT NULL due to COALESCE / LEFT side)
                       sp.supplier_name = stmt.get<std::string>(0);
                       // Column 1: product_name (TEXT, may be NULL)
                       if (stmt.is_null(1)) {
                         sp.product_name = std::nullopt;
                       } else {
                         sp.product_name = stmt.get<std::string>(1);
                       }
                       result.push_back(std::move(sp));
                     }

                     return result;
                   });

  // rows is the value returned from the lambda above
  return rows;
}

}  // namespace full_join_suppliers_products
```

