```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <optional>
#include <string>
#include <vector>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts,
                                               const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the requested SQLite database file.
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // (Re)create tables to match the supplied Department and Employee schemas.
  // Drop if they exist to keep this function self-contained and deterministic.
  conn = conn.and_then(drop_table_if_exists<Department>);
  conn = conn.and_then(drop_table_if_exists<Employee>);
  conn = conn.and_then(create_table<Department>);
  conn = conn.and_then(create_table<Employee>);

  // Insert provided data into the tables.
  conn = conn.and_then(insert(depts));
  conn = conn.and_then(insert(emps));

  JoinAnalysis analysis{};

  // Helper: run a raw SQL SELECT and map rows into JoinResult.
  auto read_join_results = [&](const std::string& sql) -> std::vector<JoinResult> {
    struct RawRow {
      std::optional<std::string> department_name;
      std::optional<std::string> first_name;
      std::optional<std::string> last_name;
      std::optional<double> salary;
    };

    auto res = conn.and_then(execute(sql))
                   .and_then(read<std::vector<RawRow>>);
    if (!res) {
      return {};
    }
    std::vector<JoinResult> out;
    out.reserve(res->size());
    for (auto& r : *res) {
      out.push_back(JoinResult{
          .department_name = std::move(r.department_name),
          .first_name = std::move(r.first_name),
          .last_name = std::move(r.last_name),
          .salary = std::move(r.salary),
      });
    }
    return out;
  };

  // INNER JOIN: employees with assigned departments.
  const std::string inner_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "INNER JOIN Employee e ON d.department_id = e.department_id;";
  analysis.inner_join_results = read_join_results(inner_sql);

  // LEFT JOIN: all employees, even without departments.
  const std::string left_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id;";
  analysis.left_join_results = read_join_results(left_sql);

  // RIGHT JOIN emulation (SQLite has no RIGHT JOIN):
  // All departments, with employees where they exist.
  const std::string right_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON d.department_id = e.department_id;";
  analysis.right_join_results = read_join_results(right_sql);

  // FULL OUTER JOIN emulation using UNION of left and right.
  const std::string full_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON d.department_id = e.department_id "
      "UNION "
      "SELECT d2.department_name, e2.first_name, e2.last_name, e2.salary "
      "FROM Employee e2 "
      "LEFT JOIN Department d2 ON e2.department_id = d2.department_id;";
  analysis.full_join_results = read_join_results(full_sql);

  return analysis;
}

}  // namespace analyze_department_employees
