```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace get_top_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string product_name;
  std::string category;
  double price;
};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Build and execute the query equivalent to:
  //
  // SELECT
  //   p.product_id,
  //   p.product_name,
  //   p.category,
  //   SUM(p.price * s.quantity) as total_sales
  // FROM Product p
  // INNER JOIN Sales s ON p.product_id = s.product_id
  // GROUP BY p.product_id, p.product_name, p.category
  // ORDER BY total_sales DESC
  // LIMIT ?;
  //
  // and read results into std::vector<TopProduct>.
  const auto result =
      conn.and_then([&](auto &c) {
            // Define aliases for the tables.
            constexpr auto p = table_alias<Product, "p">();
            constexpr auto s = table_alias<Sales, "s">();

            // Column expressions.
            auto product_id_col   = p(&Product::product_id);
            auto product_name_col = p(&Product::product_name);
            auto category_col     = p(&Product::category);
            auto price_col        = p(&Product::price);
            auto quantity_col     = s(&Sales::quantity);
            auto s_product_id_col = s(&Sales::product_id);

            // total_sales = SUM(p.price * s.quantity)
            auto total_sales_expr = sum(price_col * quantity_col).as<"total_sales">();

            // Build the select with join, group by, order by and limit.
            auto q =
                select(product_id_col,
                       product_name_col,
                       category_col,
                       total_sales_expr)
                .from(p)
                .inner_join(s, product_id_col == s_product_id_col)
                .group_by(product_id_col, product_name_col, category_col)
                .order_by(desc(total_sales_expr))
                .limit(limit_count);

            return c.execute(q) | read<std::vector<TopProduct>>;
          });

  // If anything failed, just return an empty vector.
  if (!result) {
    return {};
  }

  return *result;
}

}  // namespace get_top_products
