#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <unordered_map>

namespace update_inventory_stock {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int stock;
};

bool update_inventory_stock(const std::unordered_map<int, int>& received) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }
  auto conn = conn_res.value();

  // Ensure Product table exists (IF NOT EXISTS semantics for sqlite)
  {
    const auto create_stmt = transpilation::to_create_table<Product>();
    auto exec_res = conn->exec(create_stmt);
    if (!exec_res) {
      return false;
    }
  }

  // Begin a single transaction for all updates
  auto txn_res = begin_transaction(conn);
  if (!txn_res) {
    return false;
  }
  auto txn = txn_res.value();

  // Prepare the UPDATE statement using sqlgen
  // Equivalent SQL:
  //   UPDATE "Product"
  //   SET "stock" = "stock" + ?
  //   WHERE "product_id" = ?;
  auto update_stmt = update<Product>()
                     .set("stock"_c = "stock"_c + parameter<int>())
                     .where("product_id"_c == parameter<int>());

  // Execute UPDATE for each (product_id, quantity_received) pair
  for (const auto& [pid, qty] : received) {
    auto exec_res = exec(txn, update_stmt, qty, pid);
    if (!exec_res) {
      // On failure, do not commit; return false to signal error
      return false;
    }
  }

  // Commit transaction to ensure atomicity
  auto commit_res = commit(txn);
  return commit_res.has_value();
}

}  // namespace update_inventory_stock
