namespace create_view_order_summary {

struct Order {
  static constexpr const char* tablename = "Order";

  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
};

struct OrderItem {
  static constexpr const char* tablename = "OrderItem";

  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  double unit_price;
  int quantity;
};

struct OrderSummary {
  // For sqlgen views, follow the pattern used in tests:
  // use `viewname` instead of `tablename`.
  static constexpr const char* viewname = "OrderSummaryView";
  static constexpr bool is_view = true;

  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
  double total;
};

/**
 * Description: This function demonstrates creating a view.
 * Returns: std::vector<OrderSummary>.
 */
std::vector<OrderSummary> create_view_order_summary() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::Connection conn("test_db.sqlite");

  // Ensure base tables exist (assumed by the prompt, but we can create them
  // idempotently to be safe in an example/demo function).
  //
  // The structures correspond to:
  // Order(order_id PRIMARY KEY, customer TEXT NOT NULL)
  // OrderItem(item_id PRIMARY KEY, order_id, unit_price, quantity)
  conn.execute(R"sql(
    CREATE TABLE IF NOT EXISTS "Order"(
      order_id INTEGER PRIMARY KEY,
      customer TEXT NOT NULL
    );
  )sql");

  conn.execute(R"sql(
    CREATE TABLE IF NOT EXISTS "OrderItem"(
      item_id   INTEGER PRIMARY KEY,
      order_id  INTEGER,
      unit_price REAL NOT NULL,
      quantity  INTEGER NOT NULL
    );
  )sql");

  // Drop the view if it exists so the CREATE VIEW below succeeds
  conn.execute(R"sql(
    DROP VIEW IF EXISTS OrderSummaryView;
  )sql");

  // Create the view using CREATE VIEW AS with the given SQL
  conn.execute(R"sql(
    CREATE VIEW OrderSummaryView AS
    SELECT o.order_id,
           o.customer,
           SUM(oi.unit_price * oi.quantity) AS total
    FROM "Order" o
    INNER JOIN "OrderItem" oi ON o.order_id = oi.order_id
    GROUP BY o.order_id, o.customer;
  )sql");

  // Read from the view using sqlgen::select_from for verification
  const auto summaries = select_from<OrderSummary>().run(conn);

  return summaries;
}

}  // namespace create_view_order_summary
