```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace left_join_explicit {

struct User {
  sqlgen::PrimaryKey<int> id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> id;
  int user_id;
  std::string title;
};

struct Product {
  sqlgen::PrimaryKey<int> id;
  std::string name;
};

/**
 * This function demonstrates constructing a query using the LIKE operator.
 * It returns the generated SQL string.
 */
inline std::string like_pattern_matching() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Build a SELECT statement for Product where name LIKE 'A%'
  const auto stmt = select<Product> |
                    where("name"_c.like("A%"));

  // Generate and return the SQL string
  return to_sql(stmt);
}

/**
 * This function demonstrates a LEFT JOIN.
 * Returns: std::string.
 */
inline std::string left_join_explicit() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Explicit LEFT JOIN between User and Post on User.id = Post.user_id
  const auto stmt =
      select<User, Post> |
      from<User> |
      left_join<Post>(on("id"_c == "user_id"_c));

  return to_sql(stmt);
}

}  // namespace left_join_explicit
