```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;

  // SQLite connection to the given database file.
  sqlite::Connection conn{"test_db.sqlite"};

  // Raw SQL is used here to leverage SQLite's strftime('%w', ...) to compute weekday.
  // %w -> day of week: 0 = Sunday, 1 = Monday, ... 6 = Saturday.
  const std::string sql =
      "SELECT CAST(strftime('%w', sale_time) AS INTEGER) AS weekday, "
      "       SUM(quantity) AS total_quantity "
      "FROM Sales "
      "GROUP BY weekday "
      "ORDER BY weekday;";

  // The result rows will be mapped into WeekdayStats.
  const auto query = sqlite::Query<WeekdayStats>{sql};

  return conn.exec(query);
}

}  // namespace weekday_sales_analysis
```

