#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

// This struct represents per-row metrics (not yet weekly aggregated).
struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including
 *              day, month, year, hour, minute, second, and duration in days.
 *              It connects to the SQLite database "test_db.sqlite",
 *              assumes Project and TimeLog tables exist, and executes a query
 *              that:
 *                1. Extracts date/time components from start_time
 *                2. Computes days_between(start_time, end_time)
 *                3. Groups by project and week for reporting
 *
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;

  // Connect to SQLite database "test_db.sqlite"
  sqlite::Connection conn{"test_db.sqlite"};

  // The query uses SQLite date/time functions.
  // For weekly grouping, we use strftime('%Y-%W', start_time) as the week key.
  // We then aggregate duration_days per project/week.
  //
  // Note:
  //   - days_between is emulated as (julianday(end_time) - julianday(start_time))
  //   - For the returned TimeMetrics, we expose:
  //       * year/month/day/hour/minute/second from the *start* of the week
  //         (taken as the first day of that week)
  //       * duration_days as the total days logged in that week for that project
  //
  // If you prefer using each log’s exact start_time instead of a weekly
  // representative time, you can drop the aggregation and GROUP BY, and
  // return one row per log instead.

  const std::string sql =
      "SELECT "
      "  p.project_id AS project_id, "
      "  p.name AS name, "
      // Use the Monday of the week for reporting components
      "  CAST(strftime('%d', date(t.start_time, 'weekday 1', '-7 days')) AS INTEGER) AS day, "
      "  CAST(strftime('%m', date(t.start_time, 'weekday 1', '-7 days')) AS INTEGER) AS month, "
      "  CAST(strftime('%Y', date(t.start_time, 'weekday 1', '-7 days')) AS INTEGER) AS year, "
      "  CAST(strftime('%H', time(t.start_time)) AS INTEGER) AS hour, "
      "  CAST(strftime('%M', time(t.start_time)) AS INTEGER) AS minute, "
      "  CAST(strftime('%S', time(t.start_time)) AS INTEGER) AS second, "
      "  SUM(julianday(t.end_time) - julianday(t.start_time)) AS duration_days "
      "FROM Project p "
      "INNER JOIN TimeLog t ON p.project_id = t.project_id "
      "GROUP BY "
      "  p.project_id, "
      "  p.name, "
      "  strftime('%Y-%W', t.start_time);";

  // Execute the query and map results into TimeMetrics.
  auto stmt = sqlite::Statement{conn, sql};

  std::vector<TimeMetrics> results;
  while (stmt.step()) {
    TimeMetrics tm{};
    tm.project_id = stmt.get<int>(0);
    tm.name = stmt.get<std::string>(1);
    tm.day = stmt.get<int>(2);
    tm.month = stmt.get<int>(3);
    tm.year = stmt.get<int>(4);
    tm.hour = stmt.get<int>(5);
    tm.minute = stmt.get<int>(6);
    tm.second = stmt.get<int>(7);
    tm.duration_days = stmt.get<double>(8);
    results.emplace_back(std::move(tm));
  }

  return results;
}

}  // namespace project_time_tracking
