```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open SQLite database
  sqlite::Database db{"test_db.sqlite"};

  // Build and execute query:
  // SELECT User.user_id, User.name,
  //        COUNT(Post.post_id) AS post_count,
  //        AVG(LENGTH(Post.content)) AS avg_length
  // FROM User
  // LEFT JOIN Post ON User.user_id = Post.user_id
  // GROUP BY User.user_id, User.name;
  auto rows = db.select<User, Post>()
                    .columns(User::user_id,
                             User::name,
                             count(Post::post_id),
                             avg(length(Post::content)))
                    .left_join<Post>(User::user_id == Post::user_id)
                    .group_by(User::user_id, User::name)
                    .execute<std::tuple<int, std::string, int, std::optional<double>>>();

  std::vector<Stats> result;
  result.reserve(rows.size());

  for (const auto& row : rows) {
    const auto& [uid, name, cnt, avg_len] = row;
    Stats s{
        .user_id = uid,
        .name = name,
        .post_count = cnt,
        .avg_length = avg_len,
    };
    result.push_back(std::move(s));
  }

  return result;
}

}  // namespace group_by_with_aggregations
